import{c as t,bj as o,aQ as i,aT as a}from"./chunks/framework.BSLq2HW8.js";const p=JSON.parse('{"title":"Request Monitor","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/field-types/request-monitor.md","filePath":"documentation/field-types/request-monitor.md","lastUpdated":1771007063000}'),n={name:"documentation/field-types/request-monitor.md"};function r(s,e,l,h,c,d){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="request-monitor" tabindex="-1">Request Monitor <a class="header-anchor" href="#request-monitor" aria-label="Permalink to “Request Monitor”">​</a></h1><p>The request running in the background of the page can be detected through this field type.</p><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to “Options”">​</a></h2><table tabindex="0"><thead><tr><th>Option</th></tr></thead><tbody><tr><td><a href="#request-url">Request URL</a></td></tr><tr><td><a href="#request-url-type">Request URL Type</a></td></tr><tr><td><a href="#request-method">Request Method</a></td></tr><tr><td><a href="#timeout-to-monitor-request">Timeout to Monitor Request</a></td></tr><tr><td><a href="#if-you-want-to-check-the-request-status-code">If you want to check the Request Status Code</a></td></tr><tr><td><a href="#monitor-request-in-the-background-process">Monitor Request in the background process</a></td></tr><tr><td><a href="#do-you-want-to-click-on-an-element">Do you want to click on an element?</a></td></tr><tr><td><a href="#enter-element-selector-xpath">Enter Element Selector/Xpath</a></td></tr><tr><td><a href="#save-to-excel">Save to Excel</a></td></tr></tbody></table><h2 id="request-url" tabindex="-1">Request URL <a class="header-anchor" href="#request-url" aria-label="Permalink to “Request URL”">​</a></h2><p>The URL of the request is given in the value of this field. You can also give the URL in the <strong>default value</strong> of the field.</p><h2 id="request-url-type" tabindex="-1">Request URL Type <a class="header-anchor" href="#request-url-type" aria-label="Permalink to “Request URL Type”">​</a></h2><p>The type of the given URL is given in this option.</p><ul><li><p><strong>Match with Full URL</strong>: Matches the complete URL including protocol, domain, path, and query parameters</p><ul><li>Example: <code>https://formfiller.ctechhindi.in/example/example-8.php?id=123</code></li><li>Use this when you need to match the exact complete URL</li></ul></li><li><p><strong>Match with URL pathname</strong>: Matches only the path portion of the URL (everything after the domain)</p><ul><li>Example: <code>/example/example-8.php</code></li><li>This will match any request with this pathname, regardless of the domain or query parameters</li><li><strong>Use case</strong>: When the same API endpoint is used across different domains or environments</li><li>Full URL: <code>https://formfiller.ctechhindi.in/example/example-8.php?id=123</code></li><li>Pathname to match: <code>/example/example-8.php</code></li></ul></li><li><p><strong>Match with URL hostname</strong>: Matches only the domain/hostname portion of the URL</p><ul><li>Example: <code>formfiller.ctechhindi.in</code></li><li>This will match any request to this domain, regardless of the path or query parameters</li><li><strong>Use case</strong>: When you want to monitor all requests going to a specific domain</li><li>Full URL: <code>https://formfiller.ctechhindi.in/example/example-8.php?id=123</code></li><li>Hostname to match: <code>formfiller.ctechhindi.in</code></li></ul></li><li><p><strong>Match with RegEx</strong>: Use regular expressions for advanced URL matching patterns</p><ul><li>Example: <code>^https://.*\\.ctechhindi\\.in/api/.*$</code></li><li>Provides flexible pattern matching for complex URL structures</li><li><a href="/documentation/regex.html">Test your RegEx patterns in real-time</a></li></ul></li></ul><h2 id="request-method" tabindex="-1">Request Method <a class="header-anchor" href="#request-method" aria-label="Permalink to “Request Method”">​</a></h2><p>The type of method of the request is given in it.</p><ul><li>GET</li><li>POST</li><li>PUT</li><li>PATCH</li><li>DELETE</li><li>OPTIONS</li><li>HEAD</li></ul><h2 id="timeout-to-monitor-request" tabindex="-1">Timeout to Monitor Request <a class="header-anchor" href="#timeout-to-monitor-request" aria-label="Permalink to “Timeout to Monitor Request”">​</a></h2><p>After completion of the time given in this, this field returns false. In this the time is given in <strong>seconds</strong>.</p><h2 id="if-you-want-to-check-the-request-status-code" tabindex="-1">If you want to check the Request Status Code <a class="header-anchor" href="#if-you-want-to-check-the-request-status-code" aria-label="Permalink to “If you want to check the Request Status Code”">​</a></h2><p>After the request is completed, you can check the status code of that request through that option.</p><h2 id="monitor-request-in-the-background-process" tabindex="-1">Monitor Request in the background process <a class="header-anchor" href="#monitor-request-in-the-background-process" aria-label="Permalink to “Monitor Request in the background process”">​</a></h2><p>By default this field waits for the request to be completed and the filler does not proceed until something changes to the element. But after turning on this option, it checks the completion of the request in the <strong>background</strong> and executes the filler next field.</p><details class="details custom-block"><summary>After turning on this option, it checks the request in the background, then how to check whether the request has completed or not?</summary><p>Next in which field do you want to check whether the request has been completed or not, you can use the option given below in the settings of the field in which you want to check.</p><p><a href="/documentation/form-fields/field-settings.html#wait-until-the-response-status-of-the-given-request-monitor-fields-comes">Wait until the response status of the given request monitor fields comes</a></p></details><h2 id="do-you-want-to-click-on-an-element" tabindex="-1">Do you want to click on an element? <a class="header-anchor" href="#do-you-want-to-click-on-an-element" aria-label="Permalink to “Do you want to click on an element?”">​</a></h2><p>This is a <strong>switch field</strong> that allows you to trigger a click action on a specific element before monitoring for requests. When enabled, the extension will click on the specified element and then wait for the network request to occur.</p><p>This is useful when:</p><ul><li>You need to trigger an action (like clicking a button) that initiates a network request</li><li>The request only occurs after user interaction</li><li>You want to automate the click and monitor the request in a single field</li></ul><h2 id="enter-element-selector-xpath" tabindex="-1">Enter Element Selector/Xpath <a class="header-anchor" href="#enter-element-selector-xpath" aria-label="Permalink to “Enter Element Selector/Xpath”">​</a></h2><p>When the <strong>&quot;Do you want to click on an element?&quot;</strong> option is enabled, this field becomes available. Here you can specify the target element that should be clicked using either:</p><ul><li><strong>CSS Selector</strong>: e.g., <code>#submitButton</code>, <code>.load-data-btn</code>, <code>button[type=&quot;submit&quot;]</code></li><li><strong>XPath</strong>: e.g., <code>//button[@id=&#39;submitButton&#39;]</code>, <code>//div[@class=&#39;load-data-btn&#39;]</code></li></ul><p>The extension will locate this element and click it before starting to monitor the network requests.</p><h2 id="save-to-excel" tabindex="-1">Save to Excel <a class="header-anchor" href="#save-to-excel" aria-label="Permalink to “Save to Excel”">​</a></h2><p>This option allows you to <strong>automatically save the request response data to an Excel sheet</strong>. When enabled, the response from the monitored request will be captured and saved to your Excel file.</p><h3 id="column-naming-convention" tabindex="-1">Column Naming Convention <a class="header-anchor" href="#column-naming-convention" aria-label="Permalink to “Column Naming Convention”">​</a></h3><p>The data is saved using the following naming pattern:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>options.fieldName + &quot;||REQUEST-DATA&quot;</span></span></code></pre></div><p><strong>Example:</strong></p><ul><li>If your field name is <code>userDataRequest</code>, the Excel column will be named: <code>userDataRequest||REQUEST-DATA</code></li><li>If your field name is <code>apiResponse</code>, the Excel column will be named: <code>apiResponse||REQUEST-DATA</code></li></ul><p>This makes it easy to identify which field captured the request data and allows you to use this data in subsequent fields or for record-keeping purposes.</p><h3 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to “Use Cases”">​</a></h3><ul><li>Capturing API responses for verification</li><li>Storing dynamic data returned from server requests</li><li>Logging request data for debugging or analysis</li><li>Extracting specific information from network responses</li></ul><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to “Related Documentation”">​</a></h2><p>For advanced request monitoring using JavaScript code, see:</p><ul><li><a href="/documentation/field-types/javascript-code.html#request-monitoring">JavaScript Code - Request Monitoring</a></li></ul>',40)])])}const m=t(n,[["render",r]]);export{p as __pageData,m as default};
